1) 函数签名增加 restrict，帮助编译器假设无别名：

void sparse_matvec(int n,
  const int * __restrict rowptr,
  const int * __restrict colidx,
  const double * __restrict values,
  const double * __restrict x,
  double * __restrict y)

2) OpenMP 按行并行（行间独立）：

#pragma omp parallel for schedule(static)
for (int i=0;i<n;i++) {
  double sum=0.0;
  int start=rowptr[i], end=rowptr[i+1];
  for (int j=start;j<end;j++) {
    __builtin_prefetch(&x[colidx[j+4]], 0, 1); // 可选，需调参
    sum += values[j]*x[colidx[j]];
  }
  y[i]=sum;
}

3) 若使用 GCC/Clang，可加 -O3 -march=native -ffast-math(可选)；并确保 rowptr/colidx/values/x/y 64B 对齐（posix_memalign 或 aligned_alloc）。

由于 generate_sparse_matrix() 生成的是 j∈[i-nonzer,i+nonzer] 的带状结构，可改为存储 2*nonzer+1 条对角线（偏移 -nonzer..+nonzer），SpMV 变为近似连续访问：

// 存储：diag[k][i] 表示偏移 (k-nonzer) 的对角元素，越界为 0
// SpMV：
for i in [0,n):
  sum=0
  for off=-nonzer..+nonzer:
    j=i+off; if (0<=j<n) sum += diag[off][i]*x[j]
  y[i]=sum

这样 x 访问变为连续/可预取，内层循环可向量化（甚至用 AVX2/AVX-512）。若必须保留 CSR 接口，可在生成后检测是否为固定带宽并转换为带状格式用于计算。

double dot_product(const double* __restrict x, const double* __restrict y, int n){
  double sum=0.0;
  #pragma omp parallel for reduction(+:sum) schedule(static)
  for(int i=0;i<n;i++) sum += x[i]*y[i];
  return sum;
}

可选：
#pragma omp simd reduction(+:sum)
for(...) ...

并确保 x/y 对齐；编译选项 -O3 -march=native。

将双重索引改为行指针并加restrict：
```cpp
void jacobi_kernel(int tsteps, int n, double * __restrict A, double * __restrict B){
  for(int t=0;t<tsteps;t++){
    for(int i=1;i<n-1;i++){
      double* __restrict Bi = B + (size_t)i*n;
      const double* __restrict Ai = A + (size_t)i*n;
      const double* __restrict Aim1 = A + (size_t)(i-1)*n;
      const double* __restrict Aip1 = A + (size_t)(i+1)*n;
      #pragma omp simd aligned(Ai,Aim1,Aip1,Bi:64)
      for(int j=1;j<n-1;j++){
        Bi[j] = 0.2*(Ai[j] + Ai[j-1] + Ai[j+1] + Aip1[j] + Aim1[j]);
      }
    }
    for(int i=1;i<n-1;i++){
      double* __restrict Ai = A + (size_t)i*n;
      const double* __restrict Bi = B + (size_t)i*n;
      const double* __restrict Bim1 = B + (size_t)(i-1)*n;
      const double* __restrict Bip1 = B + (size_t)(i+1)*n;
      #pragma omp simd aligned(Ai,Bi,Bim1,Bip1:64)
      for(int j=1;j<n-1;j++){
        Ai[j] = 0.2*(Bi[j] + Bi[j-1] + Bi[j+1] + Bip1[j] + Bim1[j]);
      }
    }
  }
}
```
并建议编译：-O3 -march=native -ffast-math（或等价）以促成FMA/向量化。

